<span class="line">      <span class="token function">Item</span><span class="token punctuation">(</span><span class="token string">&quot;minecraft:diamond&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">setCount</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
